class PaymentViewModel: ObservableObject {
    @Published var cardParams = STPPaymentMethodCardParams()
    @Published var isProcessing = false
    @Published var statusMessage: String?
    @Published var paymentSuccess = false
    
    func processPayment() {
        isProcessing = true
        statusMessage = nil
        paymentSuccess = false
        
        let billingDetails = STPPaymentMethodBillingDetails()
        billingDetails.email = "demo@example.com"
        
        let paymentMethodParams = STPPaymentMethodParams(card: cardParams, billingDetails: billingDetails, metadata: nil)
        
        STPAPIClient.shared.createPaymentMethod(with: paymentMethodParams) { [weak self] paymentMethod, error in
            DispatchQueue.main.async {
                self?.isProcessing = false
                
                if let error = error {
                    self?.statusMessage = "Error: \(error.localizedDescription)"
                    self?.paymentSuccess = false
                } else if let paymentMethod = paymentMethod {
                    self?.statusMessage = "Payment Method Created: \(paymentMethod.stripeId)"
                    self?.paymentSuccess = true
                    
                    DispatchQueue.main.asyncAfter(deadline: .now() + 2) {
                        self?.statusMessage = "Demo: Payment would be processed on backend"
                    }
                }
            }
        }
    }
}

struct CardFormView: UIViewControllerRepresentable {
    @Binding var cardParams: STPPaymentMethodCardParams
    
    func makeUIViewController(context: Context) -> CardFormViewController {
        let controller = CardFormViewController()
        controller.cardParams = $cardParams
        return controller
    }
    
    func updateUIViewController(_ uiViewController: CardFormViewController, context: Context) {}
}

class CardFormViewController: UIViewController {
    var cardParams: Binding<STPPaymentMethodCardParams>?
    private let cardTextField = STPPaymentCardTextField()
    
    override func viewDidLoad() {
        super.viewDidLoad()
        
        view.backgroundColor = .white
        cardTextField.borderWidth = 1
        cardTextField.borderColor = .lightGray
        cardTextField.cornerRadius = 8
        cardTextField.translatesAutoresizingMaskIntoConstraints = false
        cardTextField.delegate = self
        
        view.addSubview(cardTextField)
        
        NSLayoutConstraint.activate([
            cardTextField.topAnchor.constraint(equalTo: view.topAnchor, constant: 20),
            cardTextField.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            cardTextField.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            cardTextField.heightAnchor.constraint(equalToConstant: 50)
        ])
    }
}

extension CardFormViewController: STPPaymentCardTextFieldDelegate {
    func paymentCardTextFieldDidChange(_ textField: STPPaymentCardTextField) {
        if let cardParams = cardParams {
            let params = STPPaymentMethodCardParams()
            params.number = textField.cardNumber
            params.expMonth = NSNumber(value: textField.expirationMonth)
            params.expYear = NSNumber(value: textField.expirationYear)
            params.cvc = textField.cvc
            cardParams.wrappedValue = params
        }
    }
}